    "inlineSchema": "generator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ==========================\n// USERS & AUTHENTICATION\n// ==========================\n\nmodel User {\n  id String @id @default(cuid())\n\n  email String @unique\n\n  password String\n\n  isActive Boolean @default(true)\n\n  roles UserRole[]\n\n  director Director?\n\n  teacher Teacher?\n\n  parent Parent?\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\n// ==========================\n// ROLES & PERMISSIONS\n// ==========================\n\nmodel Role {\n  id String @id @default(cuid())\n\n  name String @unique\n\n  description String?\n\n  users UserRole[]\n\n  permissions RolePermission[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\nmodel Permission {\n  id String @id @default(cuid())\n\n  name String @unique\n\n  description String?\n\n  roles RolePermission[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\n// ==========================\n// USER ROLE CONNECTION\n// ==========================\n\nmodel UserRole {\n  id String @id @default(cuid())\n\n  userId String\n\n  roleId String\n\n  user User @relation(fields: [userId], references: [id])\n\n  role Role @relation(fields: [roleId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  @@unique([userId, roleId])\n}\n\n// ==========================\n// ROLE PERMISSION CONNECTION\n// ==========================\n\nmodel RolePermission {\n  id String @id @default(cuid())\n\n  roleId String\n\n  permissionId String\n\n  role Role @relation(fields: [roleId], references: [id])\n\n  permission Permission @relation(fields: [permissionId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  @@unique([roleId, permissionId])\n}\n\n// ==========================\n// DIRECTOR\n// ==========================\n\nmodel Director {\n  id String @id @default(cuid())\n\n  firstName String\n\n  lastName String\n\n  phone String?\n\n  userId String @unique\n\n  user User @relation(fields: [userId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\n// ==========================\n// TEACHERS\n// ==========================\n\nmodel Teacher {\n  id String @id @default(cuid())\n\n  firstName String\n\n  lastName String\n\n  phone String?\n\n  userId String @unique\n\n  user User @relation(fields: [userId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\n// ==========================\n// PARENTS\n// ==========================\n\nmodel Parent {\n  id String @id @default(cuid())\n\n  firstName String\n\n  lastName String\n\n  phone String?\n\n  relationship String?\n  // Father\n  // Mother\n  // Guardian\n\n  userId String @unique\n\n  user User @relation(fields: [userId], references: [id])\n\n  students StudentParent[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\n// ==========================\n// STUDENTS\n// ==========================\n\nmodel Student {\n  id String @id @default(cuid())\n\n  admissionNumber String @unique\n\n  firstName String\n\n  lastName String\n\n  dateOfBirth DateTime?\n\n  gender String?\n\n  isActive Boolean @default(true)\n\n  academicYearId String?\n\n  termId String?\n\n  classId String?\n\n  studentCategoryId String?\n\n  academicYear AcademicYear? @relation(fields: [academicYearId], references: [id])\n\n  term Term? @relation(fields: [termId], references: [id])\n\n  schoolClass SchoolClass? @relation(fields: [classId], references: [id])\n\n  studentCategory StudentCategory? @relation(fields: [studentCategoryId], references: [id])\n\n  parents StudentParent[]\n\n  payments Payment[]\n\n  termFees StudentTermFee[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\n// ==========================\n// STUDENT - PARENT RELATION\n// ==========================\n\nmodel StudentParent {\n  id String @id @default(cuid())\n\n  studentId String\n\n  parentId String\n\n  relationship String?\n  // Father\n  // Mother\n  // Guardian\n\n  student Student @relation(fields: [studentId], references: [id])\n\n  parent Parent @relation(fields: [parentId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  @@unique([studentId, parentId])\n}\n\n// ==========================\n// ACADEMIC SETUP & FEES\n// ==========================\n\nmodel AcademicYear {\n  id String @id @default(cuid())\n\n  name String @unique\n\n  isActive Boolean @default(true)\n\n  terms Term[]\n\n  financeStructures FinanceStructure[]\n\n  students Student[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\nmodel Term {\n  id String @id @default(cuid())\n\n  name String\n  // e.g., \"Term 1 2024\", \"Term 2 2024\"\n\n  academicYearId String\n\n  feeAmount Int @default(0)\n  // e.g., 1000000 for 1 million shillings\n\n  startDate DateTime?\n\n  endDate DateTime?\n\n  isActive Boolean @default(true)\n\n  academicYear AcademicYear @relation(fields: [academicYearId], references: [id])\n\n  studentTermFees StudentTermFee[]\n\n  financeStructures FinanceStructure[]\n\n  students Student[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n\n  @@unique([academicYearId, name])\n}\n\nmodel SchoolClass {\n  id String @id @default(cuid())\n\n  name String @unique\n\n  isActive Boolean @default(true)\n\n  students Student[]\n\n  financeStructures FinanceStructure[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\nmodel StudentCategory {\n  id String @id @default(cuid())\n\n  name String @unique\n\n  isActive Boolean @default(true)\n\n  students Student[]\n\n  financeStructures FinanceStructure[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\nmodel FeeType {\n  id String @id @default(cuid())\n\n  name String @unique\n\n  isActive Boolean @default(true)\n\n  financeStructures FinanceStructure[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\nmodel FinanceStructure {\n  id String @id @default(cuid())\n\n  academicYearId String\n\n  termId String\n\n  classId String\n\n  studentCategoryId String\n\n  feeTypeId String\n\n  expectedAmount Int\n\n  academicYear AcademicYear @relation(fields: [academicYearId], references: [id])\n\n  term Term @relation(fields: [termId], references: [id])\n\n  schoolClass SchoolClass @relation(fields: [classId], references: [id])\n\n  studentCategory StudentCategory @relation(fields: [studentCategoryId], references: [id])\n\n  feeType FeeType @relation(fields: [feeTypeId], references: [id])\n\n  payments Payment[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n\n  @@unique([academicYearId, termId, classId, studentCategoryId, feeTypeId])\n}\n\nmodel StudentTermFee {\n  id String @id @default(cuid())\n\n  studentId String\n\n  termId String\n\n  amountOwed Int\n\n  amountPaid Int @default(0)\n\n  student Student @relation(fields: [studentId], references: [id])\n\n  term Term @relation(fields: [termId], references: [id])\n\n  payments Payment[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n\n  @@unique([studentId, termId])\n}\n\nmodel Payment {\n  id String @id @default(cuid())\n\n  studentId String\n\n  studentTermFeeId String?\n\n  financeStructureId String?\n\n  amount Int\n\n  method String\n\n  status String @default(\"completed\")\n\n  description String?\n\n  date DateTime @default(now())\n\n  student Student @relation(fields: [studentId], references: [id])\n\n  studentTermFee StudentTermFee? @relation(fields: [studentTermFeeId], references: [id])\n\n  financeStructure FinanceStructure? @relation(fields: [financeStructureId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n",
